CREATE TABLE IF NOT EXISTS employer_profiles (user_id BIGINT UNSIGNED NOT NULL,full_name VARCHAR(150) NOT NULL,phone VARCHAR(30) NULL,organisation VARCHAR(180) NULL,created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,PRIMARY KEY(user_id),CONSTRAINT fk_employer_user FOREIGN KEY(user_id) REFERENCES users(id) ON DELETE CASCADE) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS placements (id BIGINT UNSIGNED NOT NULL AUTO_INCREMENT,employer_user_id BIGINT UNSIGNED NOT NULL,candidate_user_id BIGINT UNSIGNED NOT NULL,role_title VARCHAR(180) NOT NULL,status ENUM('active','probation','completed','terminated') NOT NULL DEFAULT 'active',start_date DATE NOT NULL,end_date DATE NULL,created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,PRIMARY KEY(id),KEY idx_placement_employer(employer_user_id,status),CONSTRAINT fk_place_employer FOREIGN KEY(employer_user_id) REFERENCES users(id),CONSTRAINT fk_place_candidate FOREIGN KEY(candidate_user_id) REFERENCES users(id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS replacement_requests (id BIGINT UNSIGNED NOT NULL AUTO_INCREMENT,placement_id BIGINT UNSIGNED NOT NULL,employer_user_id BIGINT UNSIGNED NOT NULL,reason TEXT NOT NULL,status ENUM('new','reviewing','approved','matching','resolved','declined') NOT NULL DEFAULT 'new',created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,PRIMARY KEY(id),KEY idx_replacement_employer(employer_user_id,status),CONSTRAINT fk_replacement_place FOREIGN KEY(placement_id) REFERENCES placements(id),CONSTRAINT fk_replacement_employer FOREIGN KEY(employer_user_id) REFERENCES users(id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS contract_extensions (id BIGINT UNSIGNED NOT NULL AUTO_INCREMENT,placement_id BIGINT UNSIGNED NOT NULL,employer_user_id BIGINT UNSIGNED NOT NULL,requested_end_date DATE NOT NULL,note VARCHAR(1000) NULL,status ENUM('new','reviewing','approved','declined') NOT NULL DEFAULT 'new',created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,PRIMARY KEY(id),KEY idx_extension_employer(employer_user_id,status),CONSTRAINT fk_extension_place FOREIGN KEY(placement_id) REFERENCES placements(id),CONSTRAINT fk_extension_employer FOREIGN KEY(employer_user_id) REFERENCES users(id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS payments (id BIGINT UNSIGNED NOT NULL AUTO_INCREMENT,employer_user_id BIGINT UNSIGNED NOT NULL,reference_code VARCHAR(40) NOT NULL,amount DECIMAL(12,2) NOT NULL,currency CHAR(3) NOT NULL DEFAULT 'KES',status ENUM('pending','paid','failed','refunded') NOT NULL,paid_at DATETIME NULL,created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,PRIMARY KEY(id),UNIQUE KEY uq_payment_reference(reference_code),KEY idx_payment_employer(employer_user_id,created_at),CONSTRAINT fk_payment_employer FOREIGN KEY(employer_user_id) REFERENCES users(id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS reviews (id BIGINT UNSIGNED NOT NULL AUTO_INCREMENT,user_id BIGINT UNSIGNED NOT NULL,placement_id BIGINT UNSIGNED NULL,rating TINYINT UNSIGNED NOT NULL,review_text TEXT NOT NULL,status ENUM('pending','published','rejected') NOT NULL DEFAULT 'pending',created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,PRIMARY KEY(id),KEY idx_reviews_status(status,created_at),CONSTRAINT fk_review_user FOREIGN KEY(user_id) REFERENCES users(id),CONSTRAINT fk_review_placement FOREIGN KEY(placement_id) REFERENCES placements(id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS articles (id BIGINT UNSIGNED NOT NULL AUTO_INCREMENT,slug VARCHAR(180) NOT NULL,title VARCHAR(220) NOT NULL,excerpt VARCHAR(500) NOT NULL,body MEDIUMTEXT NOT NULL,status ENUM('draft','published','archived') NOT NULL DEFAULT 'draft',published_at DATETIME NULL,updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,PRIMARY KEY(id),UNIQUE KEY uq_articles_slug(slug),KEY idx_articles_public(status,published_at)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS site_settings (setting_key VARCHAR(100) NOT NULL,setting_value TEXT NOT NULL,updated_by BIGINT UNSIGNED NULL,updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,PRIMARY KEY(setting_key),CONSTRAINT fk_setting_user FOREIGN KEY(updated_by) REFERENCES users(id) ON DELETE SET NULL) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS email_outbox (id BIGINT UNSIGNED NOT NULL AUTO_INCREMENT,recipient VARCHAR(254) NOT NULL,subject VARCHAR(255) NOT NULL,html MEDIUMTEXT NOT NULL,status ENUM('pending','sending','sent','failed') NOT NULL DEFAULT 'pending',attempts TINYINT UNSIGNED NOT NULL DEFAULT 0,last_error VARCHAR(1000) NULL,available_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,sent_at DATETIME NULL,created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,PRIMARY KEY(id),KEY idx_email_delivery(status,available_at)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS job_alerts (user_id BIGINT UNSIGNED NOT NULL,enabled BOOLEAN NOT NULL DEFAULT TRUE,profession VARCHAR(120) NULL,location VARCHAR(160) NULL,PRIMARY KEY(user_id),CONSTRAINT fk_alert_user FOREIGN KEY(user_id) REFERENCES users(id) ON DELETE CASCADE) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
